## Code Example

```javascript
// Create per-tenant CMK and bucket with Object Lock enabled (AWS SDK v3)
const { KMSClient, CreateKeyCommand } = require('@aws-sdk/client-kms');
const { S3Client, CreateBucketCommand, PutObjectLockConfigurationCommand } = require('@aws-sdk/client-s3');

async function setupTenantResidency(tenantId, homeRegion) {
  const kmsClient = new KMSClient({ region: homeRegion });
  const s3Client = new S3Client({ region: homeRegion });

  // Create per-tenant CMK with restricted key policy
  const key = await kmsClient.send(new CreateKeyCommand({
    Description: `CMK for tenant ${tenantId}`,
    KeyUsage: 'ENCRYPT_DECRYPT',
    KeySpec: 'SYMMETRIC_DEFAULT',
    MultiRegion: false // Enforce single-region residency
  }));

  // Create tenant bucket with Object Lock (requires versioned bucket)
  await s3Client.send(new CreateBucketCommand({
    Bucket: `tenant-${tenantId}-backups`,
    ObjectLockEnabledForBucket: true
  }));

  // Apply Object Lock configuration for compliance immutability
  await s3Client.send(new PutObjectLockConfigurationCommand({
    Bucket: `tenant-${tenantId}-backups`,
    ObjectLockConfiguration: {
      ObjectLockEnabled: 'Enabled',
      Rule: { DefaultRetention: { Mode: 'COMPLIANCE', Days: 90 } }
    }
  }));

  return { keyId: key.KeyMetadata.KeyId };
}
```

