// Node.js: fetch ReplicaLag metric from CloudWatch for us-east-1 Aurora replica
const AWS = require('aws-sdk');
const cw = new AWS.CloudWatch({region: 'us-east-1'});
async function getLag() {
  const res = await cw.getMetricStatistics({
    Namespace: 'AWS/RDS',
    MetricName: 'ReplicaLag',
    Dimensions: [{ Name: 'DBInstanceIdentifier', Value: 'mydb-replica-us-east' }],
    StartTime: new Date(Date.now() - 5 * 60 * 1000),
    EndTime: new Date(),
    Period: 60,
    Statistics: ['Average']
  }).promise();
  return res.Datapoints?.[0]?.Average ?? 0;
}
```

